IDENTIFIER_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")

ALLOWED_OPERATORS = {
    "=": "=",
    "!=": "!=",
    "<>": "<>",
    "<": "<",
    "<=": "<=",
    ">": ">",
    ">=": ">=",
    "like": "LIKE",
    "ilike": "ILIKE",
    "in": "IN",
    "not in": "NOT IN",
    "is": "IS",
    "is not": "IS NOT",
}

ALLOWED_LOGICALS = {"and": "AND", "or": "OR"}


def get_conn():
    return psycopg2.connect(**DB_CONFIG)


def validate_identifier(name):
    if not isinstance(name, str) or not IDENTIFIER_RE.match(name):
        raise ValueError(f"Invalid identifier: {name}")
    return name


def quote_ident(name):
    return psycopg2.extensions.quote_ident(name, None)


def build_where_clause(filters, params):
    if not filters:
        return "", params

    if not isinstance(filters, list):
        raise ValueError("filters must be a list")

    clauses = []
    for idx, f in enumerate(filters):
        if not isinstance(f, dict):
            raise ValueError("Each filter must be an object")

        column = validate_identifier(f.get("column"))
        operator = str(f.get("operator", "=")).strip().lower()
        value = f.get("value")
        logical = str(f.get("logical", "and")).strip().lower()

        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Unsupported operator: {operator}")
        if logical not in ALLOWED_LOGICALS and idx != len(filters) - 1:
            raise ValueError(f"Unsupported logical operator: {logical}")

        sql_op = ALLOWED_OPERATORS[operator]
        col_sql = quote_ident(column)

        if operator in {"in", "not in"}:
            if not isinstance(value, (list, tuple)) or len(value) == 0:
                raise ValueError(f"{operator} requires a non-empty list value")
            placeholders = []
            for v in value:
                params.append(v)
                placeholders.append(f"%s")
            clause = f"{col_sql} {sql_op} ({', '.join(placeholders)})"
        elif operator in {"is", "is not"}:
            if value is None:
                clause = f"{col_sql} {sql_op} NULL"
            elif isinstance(value, str) and value.lower() == "null":
                clause = f"{col_sql} {sql_op} NULL"
            else:
                params.append(value)
                clause = f"{col_sql} {sql_op} %s"
        else:
            params.append(value)
            clause = f"{col_sql} {sql_op} %s"

        clauses.append(clause)
        if idx < len(filters) - 1:
            clauses.append(ALLOWED_LOGICALS.get(logical, "AND"))

    return " WHERE " + " ".join(clauses), params


@app.route("/query", methods=["POST"])
def query_table():
    try:
        payload = request.get_json(force=True, silent=False)
        if not isinstance(payload, dict):
            return jsonify({"error": "Invalid JSON payload"}), 400

        table = validate_identifier(payload.get("table"))
        columns = payload.get("columns", ["*"])
        filters = payload.get("filters", [])
        limit = payload.get("limit", 100)
        offset = payload.get("offset", 0)
        order_by = payload.get("order_by", [])
        distinct = bool(payload.get("distinct", False))

        if columns == ["*"] or columns == "*":
            select_sql = "*"
        else:
            if not isinstance(columns, list) or not columns:
                return jsonify({"error": "columns must be a non-empty list or *"}), 400
            select_sql = ", ".join(quote_ident(validate_identifier(c)) for c in columns)

        if not isinstance(limit, int) or limit < 1 or limit > 10000:
            return jsonify({"error": "limit must be an integer between 1 and 10000"}), 400
        if not isinstance(offset, int) or offset < 0:
            return jsonify({"error": "offset must be a non-negative integer"}), 400

        order_sql = ""
        if order_by:
            if not isinstance(order_by, list):
                return jsonify({"error": "order_by must be a list"}), 400
            parts = []
            for item in order_by:
                if isinstance(item, str):
                    col = validate_identifier(item)
                    direction = "ASC"
                elif isinstance(item, dict):
                    col = validate_identifier(item.get("column"))
                    direction = str(item.get("direction", "asc")).strip().upper()
                    if direction not in {"ASC", "DESC"}:
                        return jsonify({"error": "order_by direction must be ASC or DESC"}), 400
                else:
                    return jsonify({"error": "Invalid order_by item"}), 400
                parts.append(f"{quote_ident(col)} {direction}")
            order_sql = " ORDER BY " + ", ".join(parts)

        params = []
        where_sql, params = build_where_clause(filters, params)

        distinct_sql = "DISTINCT " if distinct else ""
        sql = f"SELECT {distinct_sql}{select_sql} FROM {quote_ident(table)}{where_sql}{order_sql} LIMIT %s OFFSET %s"
        params.extend([limit, offset])

        with get_conn() as conn:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(sql, params)
                rows = cur.fetchall()

        return jsonify({
            "table": table,
            "count": len(rows),
            "data": rows,
        }), 200

    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({"error": "Database error", "detail": str(e)}), 500
    except Exception as e:
        return jsonify({"error": "Internal server error", "detail": str(e)}), 500


